                NavigationBarItem(
                    icon = {
                        BadgedBox(
                            badge = {
                                if (unreadCount > 0) {
                                    Badge { Text("$unreadCount") }
                                }
                            }
                        ) {
                            Icon(Icons.Filled.Settings, contentDescription = "Settings")
                        }
                    },
                    label = { Text("Settings") },
                    selected = currentTab == 3,
                    onClick = {
                        currentTab = 3
                        settingsViewModel.refreshNotifications()
                    }
                )
            }
        }
    ) { paddingValues ->
        when (currentTab) {
            0 -> OffersScreen(
                viewModel = offersViewModel,
